import { settings } from './settings';
import { writable } from 'svelte/store';

export const usedHints = writable(0);

// 默认提示次数
const DEFAULT_HINTS = 5;

export const hints = writable(DEFAULT_HINTS);

// 监听设置变化
settings.subscribe(($settings) => {
	if ($settings.hintsLimited) {
		hints.update($hints => {
			if ($hints > DEFAULT_HINTS) return DEFAULT_HINTS;
			return $hints;
		});
	}
});

// 导出函数
export function useHint() {
	let success = false;
	hints.update($hints => {
		if ($hints > 0) {
			$hints--;
			success = true;
		}
		return $hints;
	});
	
	if (success) {
		usedHints.update($usedHints => $usedHints + 1);
	}
	
	return success;
}

export function resetHints() {
	hints.set(DEFAULT_HINTS);
	usedHints.set(0);
}